const ITEM_RARITIES = {
    common: { label: "Common", color: "#9E9E9E" },
    uncommon: { label: "Uncommon", color: "#FFFF55" },
    rare: { label: "Rare", color: "#5555FF" },
    epic: { label: "Epic", color: "#AA00AA" }
};

function getItems() {
    return ITEMS;
}

function getItemById(id) {
    return ITEMS.find(i => i.id === id);
}

function getItemsByCategory(category) {
    if (!category) return ITEMS;
    return ITEMS.filter(i => i.category === category);
}

function getItemsByRarity(rarity) {
    if (!rarity) return ITEMS;
    return ITEMS.filter(i => i.rarity === rarity);
}

function searchItems(query) {
    const q = query.toLowerCase();
    return ITEMS.filter(i =>
        i.name.toLowerCase().includes(q) ||
        i.id.toLowerCase().includes(q) ||
        i.category.toLowerCase().includes(q)
    );
}

function populateItemCategories(selectElement) {
    const categories = [...new Set(ITEMS.map(i => i.category))];
    selectElement.innerHTML = '<option value="">All Categories</option>';
    categories.sort().forEach(cat => {
        const opt = document.createElement('option');
        opt.value = cat;
        opt.textContent = ITEM_CATEGORIES[cat] || cat;
        selectElement.appendChild(opt);
    });
}

if (typeof module !== 'undefined' && module.exports) {
    module.exports = { ITEMS, ITEM_CATEGORIES, ITEM_RARITIES, getItems, getItemById, getItemsByCategory, getItemsByRarity, searchItems, populateItemCategories };
}